#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <signal.h>
#include <time.h>
#include <unistd.h>
#include <pigpio.h>

// Define DHT11 sensor GPIO pin
#define DHT11_PIN 7

// Global flag to indicate program termination
volatile sig_atomic_t terminate = 0;

// Signal handler function
void signal_handler(int signal) {
    printf("Caught signal %d, terminating program...\n", signal);
    terminate = 1;
}

// Function to read data from DHT11 sensor
int read_dht11(int pin, float *temperature, float *humidity) {
    int data[5] = {0, 0, 0, 0, 0};
    int laststate = PI_LOW;
    int j = 0;
    int i;

    // Set GPIO pin as output
    gpioSetMode(pin, PI_OUTPUT);

    // Send start signal
    gpioWrite(pin, PI_LOW);
    gpioDelay(1000); // 1ms
    gpioWrite(pin, PI_HIGH);
    gpioDelay(40); // 40us

    // Set GPIO pin as input
    gpioSetMode(pin, PI_INPUT);

    // Wait for the sensor to pull the pin low
    for (i = 0; i < 85; i++) {
        int count = 0;
        while (gpioRead(pin) == laststate) {
            count++;
            gpioDelay(1);
            if (count == 255) {
                return -1; // Timeout
            }
        }
        laststate = gpioRead(pin);

        if (count == 255) {
            return -1; // Timeout
        }

        // Record the transition time (pulse width)
        if ((i > 3) && (i % 2 == 0)) {
            data[j / 8] <<= 1;
            if (count > 20) {
                data[j / 8] |= 1;
            }
            j++;
        }
    }

    // Check for checksum error
    if ((data[4] != ((data[0] + data[1] + data[2] + data[3]) & 0xFF))) {
        return -1; // Checksum error
    }

    // Convert data to temperature and humidity
    *humidity = (float)((data[0] << 8) + data[1]) / 10.0;
    *temperature = (float)(((data[2] & 0x7F) << 8) + data[3]) / 10.0;
    if (data[2] & 0x80) {
        *temperature *= -1;
    }

    return 0; // Success
}

// Function to display temperature and humidity data with timestamp
void display_data(float temperature, float humidity) {
    time_t now = time(NULL);
    struct tm *t = localtime(&now);
    char timestamp[20];
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", t);

    printf("[%s] Temperature: %.1f\u00b0C, Humidity: %.1f%%\n", timestamp, temperature, humidity);
}

int main() {
    // Initialize pigpio library
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Set signal handlers for graceful termination
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    // Main loop
    while (!terminate) {
        float temperature, humidity;
        int result;

        // Read DHT11 sensor data
        result = read_dht11(DHT11_PIN, &temperature, &humidity);

        // Handle sensor read errors
        if (result != 0) {
            fprintf(stderr, "DHT11 sensor read failed\n");
        } else {
            // Display temperature and humidity data
            display_data(temperature, humidity);
        }

        // Wait 5 seconds
        sleep(5);
    }

    // Terminate pigpio library
    gpioTerminate();

    return 0;
}

