// Constants
#define DHT11_GPIO 7
#define READ_DELAY 5 // Seconds
#define MAX_RETRIES 3

// Global variable for graceful shutdown
volatile sig_atomic_t terminate = 0;

// Signal handler for Ctrl+C
void signal_handler(int signal) {
    terminate = 1;
    printf("\nCaught signal %d, terminating gracefully...\n", signal);
}

// Function to read data from DHT11 sensor
int read_dht11(int gpio, float *temperature, float *humidity) {
    int retries = 0;
    int data[5] = {0};
    int i, j;

    while (retries < MAX_RETRIES) {
        // Reset the DHT11
        gpioSetMode(gpio, PI_OUTPUT);
        gpioWrite(gpio, 0);
        gpioDelay(1000); // 1ms
        gpioWrite(gpio, 1);
        gpioDelay(30); // 20-40us
        gpioSetMode(gpio, PI_INPUT);

        // Wait for DHT11 to pull down the data line
        uint32_t start = 0, end = 0;
        int timeout = 0;
        for (i = 0; i < 85; i++) {
            timeout = 0;
            while (gpioRead(gpio) == 1) {
                gpioDelay(1);
                if (++timeout > 100) {
                    fprintf(stderr, "DHT11 timeout 1\n");
                    return -1; // Timeout
                }
            }
            start = gpioTick();

            timeout = 0;
            while (gpioRead(gpio) == 0) {
                gpioDelay(1);
                if (++timeout > 100) {
                    fprintf(stderr, "DHT11 timeout 2\n");
                    return -1; // Timeout
                }
            }
            end = gpioTick();

            data[i / 8] <<= 1;
            if (end - start > 40) {
                data[i / 8] |= 1;
            }
        }

        // Validate checksum
        if (data[4] != ((data[0] + data[1] + data[2] + data[3]) & 0xFF)) {
            fprintf(stderr, "DHT11 checksum error\n");
            retries++;
            gpioDelay(500); // Wait before retrying
            continue;
        }

        // Calculate temperature and humidity
        *humidity = (float)(((data[0] << 8) + data[1]) / 10.0);
        *temperature = (float)(((data[2] << 8) + data[3]) / 10.0);

        return 0; // Success
    }

    fprintf(stderr, "DHT11 read failed after %d retries\n", MAX_RETRIES);
    return -1; // Failure
}

// Function to display sensor data
void display_data(float temperature, float humidity) {
    time_t now = time(NULL);
    struct tm *t = localtime(&now);
    char timestamp[32];
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", t);

    printf("%s - Temperature: %.1f C, Humidity: %.1f %%\n", timestamp, temperature, humidity);
}

int main() {
    float temperature, humidity;
    int init_result;

    // Initialize pigpio library
    init_result = gpioInitialise();
    if (init_result < 0) {
        fprintf(stderr, "pigpio initialisation failed: %d\n", init_result);
        return 1;
    }

    // Set signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    // Main loop
    while (!terminate) {
        if (read_dht11(DHT11_GPIO, &temperature, &humidity) == 0) {
            display_data(temperature, humidity);
        } else {
            fprintf(stderr, "Error reading DHT11 sensor\n");
        }

        sleep(READ_DELAY);
    }

    // Terminate pigpio library
    gpioTerminate();

    return 0;
}

