#define DHT11_PIN 7
#define READ_ERROR_DELAY 10000 // 10 seconds
#define MIN_TEMP -40
#define MAX_TEMP 80
#define MIN_HUMIDITY 0
#define MAX_HUMIDITY 100

static volatile int keep_running = 1;

void signal_handler(int signal)
{
    fprintf(stderr, "\nCaught signal %d, exiting gracefully.\n", signal);
    keep_running = 0;
}

// Function to initialize the pigpio library
int initialize_pigpio()
{
    if (gpioInitialise() < 0)
    {
        fprintf(stderr, "pigpio initialisation failed\n");
        return -1;
    }
    return 0;
}

// Function to read data from the DHT11 sensor
int read_dht11(int pin, int *temperature, int *humidity)
{
    int data[5] = {0, 0, 0, 0, 0};
    int laststate = PI_LOW;
    int j = 0;
    int i;

    gpioSetMode(pin, PI_OUTPUT);
    gpioWrite(pin, PI_LOW);
    gpioDelay(1);
    gpioWrite(pin, PI_HIGH);
    gpioDelay(40);
    gpioSetMode(pin, PI_INPUT);

    // Wait for the DHT11 to pull the line low
    for (i = 0; i < 85; i++)
    {
        int counter = 0;
        while (gpioRead(pin) == laststate)
        {
            gpioDelay(1);
            counter++;
            if (counter > 100)
            {
                fprintf(stderr, "DHT11 Timeout\n");
                return -1;
            }
        }
        laststate = gpioRead(pin);

        if (i >= 3 && i % 2 == 0)
        {
            data[j / 8] <<= 1;
            if (counter > 16)
                data[j / 8] |= 1;
            j++;
        }
    }

    // Verify checksum
    if ((data[0] + data[1] + data[2] + data[3]) & 0xFF != data[4])
    {
        fprintf(stderr, "DHT11 Checksum error\n");
        return -1;
    }

    *humidity = (data[0] * 256 + data[1]) / 10.0;
    *temperature = (data[2] * 256 + data[3]) / 10.0;

    return 0;
}

// Function to display the temperature and humidity data
void display_data(int temperature, int humidity)
{
    time_t now = time(NULL);
    struct tm *t = localtime(&now);
    char timestamp[20];

    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", t);

    printf("[%s] Temperature: %d.%02d C, Humidity: %d.%02d %%\n",
           timestamp, temperature / 10, temperature % 10, humidity / 10, humidity % 10);
}

// Function to clean up resources before exiting
void cleanup()
{
    gpioTerminate();
}

int main()
{
    int temperature, humidity;

    // Register signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    // Initialize pigpio
    if (initialize_pigpio() != 0)
    {
        return 1;
    }

    // Main loop
    while (keep_running)
    {
        if (read_dht11(DHT11_PIN, &temperature, &humidity) == 0)
        {
            // Check if the data is within the valid range
            if (temperature >= MIN_TEMP && temperature <= MAX_TEMP &&
                humidity >= MIN_HUMIDITY && humidity <= MAX_HUMIDITY)
            {
                display_data(temperature, humidity);
            }
            else
            {
                fprintf(stderr, "Invalid DHT11 data: Temperature=%d, Humidity=%d\n", temperature, humidity);
            }
        }
        else
        {
            fprintf(stderr, "Failed to read DHT11 data, retrying in %d seconds\n", READ_ERROR_DELAY / 1000);
            gpioDelay(READ_ERROR_DELAY); // Wait for 10 seconds before retrying
        }

        gpioDelay(5000); // Wait 5 seconds
    }

    // Clean up resources before exiting
    cleanup();

    return 0;
}

