// Define GPIO pins
#define TOUCH_SENSOR_1 25
#define TOUCH_SENSOR_2 24
#define TOUCH_SENSOR_3 23
#define RELAY_PIN 26

// Define debounce time in milliseconds
#define DEBOUNCE_TIME 50

// Global variables
volatile int relay_state = 0; // 0: OFF, 1: ON
volatile int touch_count = 0;
FILE *log_file = NULL;

// Function prototypes
int initialize_gpio();
int configure_interrupts(int pin);
void touch_callback(int gpio, int level, uint32_t tick, void *user);
void log_event(int touch_sensor, int relay_state);
void cleanup_gpio();
void signal_handler(int signal);

// Function to initialize GPIO pins
int initialize_gpio() {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    gpioSetMode(TOUCH_SENSOR_1, PI_INPUT);
    gpioSetMode(TOUCH_SENSOR_2, PI_INPUT);
    gpioSet_t trigger = RISING_EDGE;
    gpioSetISFuncEx(TOUCH_SENSOR_1, trigger, 0, touch_callback, NULL);
    gpioSetISFuncEx(TOUCH_SENSOR_2, trigger, 0, touch_callback, NULL);
    gpioSetISFuncEx(TOUCH_SENSOR_3, trigger, 0, touch_callback, NULL);

    gpioSetMode(RELAY_PIN, PI_OUTPUT);
    gpioWrite(RELAY_PIN, 0); // Initialize relay to OFF state

    return 0;
}

// Function to configure interrupts for a specific GPIO pin
int configure_interrupts(int pin) {
    // Set GPIO pin to input mode
    if (gpioSetMode(pin, PI_INPUT) != 0) {
        fprintf(stderr, "Failed to set GPIO %d to input mode\n", pin);
        return 1;
    }

    // Set interrupt function for rising edge
    gpioSetISFuncEx(pin, RISING_EDGE, 0, touch_callback, NULL);

    return 0;
}

// Function to handle touch sensor interrupts
void touch_callback(int gpio, int level, uint32_t tick, void *user) {
    static uint32_t last_tick = 0;

    // Debounce the touch event
    uint32_t current_tick = gpioTick();
    if (current_tick - last_tick < DEBOUNCE_TIME) {
        return;
    }
    last_tick = current_tick;

    // Determine which touch sensor triggered the interrupt
    int touch_sensor;
    if (gpio == TOUCH_SENSOR_1) {
        touch_sensor = 1;
    } else if (gpio == TOUCH_SENSOR_2) {
        touch_sensor = 2;
    } else if (gpio == TOUCH_SENSOR_3) {
        touch_sensor = 3;
    } else {
        fprintf(stderr, "Invalid GPIO pin: %d\n", gpio);
        return;
    }

    // Toggle the relay state
    relay_state = !relay_state;
    gpioWrite(RELAY_PIN, relay_state);

    // Log the event
    log_event(touch_sensor, relay_state);

    // Increment the touch count
    touch_count++;
}

// Function to log events to the log file
void log_event(int touch_sensor, int relay_state) {
    time_t rawtime;
    struct tm *timeinfo;
    char timestamp[80];

    time(&rawtime);
    timeinfo = localtime(&rawtime);

    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

    if (log_file != NULL) {
        fprintf(log_file, "%s - Touch Sensor %d: Relay State = %s\n", timestamp, touch_sensor, relay_state ? "ON" : "OFF");
        fflush(log_file); // Ensure the log is written immediately
    } else {
        fprintf(stderr, "Log file is not open\n");
    }
}

// Function to cleanup GPIO pins
void cleanup_gpio() {
    printf("Cleaning up GPIO...\n");
    gpioWrite(RELAY_PIN, 0); // Ensure relay is OFF
    gpioTerminate();
    if (log_file != NULL) {
        fclose(log_file);
    }
    printf("GPIO cleanup complete.\n");
}

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    printf("Signal received (%d). Shutting down...\n", signal);
    cleanup_gpio();
    exit(0);
}

int main() {
    // Set up signal handling for Ctrl+C and SIGTERM
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    // Initialize GPIO
    if (initialize_gpio() != 0) {
        fprintf(stderr, "GPIO initialization failed. Exiting.\n");
        return 1;
    }

    // Open the log file
    log_file = fopen("touch_relay.log", "a");
    if (log_file == NULL) {
        fprintf(stderr, "Failed to open log file. Exiting.\n");
        cleanup_gpio();
        return 1;
    }

    printf("Touch-activated relay control started. Press Ctrl+C to exit.\n");

    // Keep the program running until a signal is received
    while (1) {
        sleep(1); // Sleep to reduce CPU usage
    }

    return 0;
}

