int read_temperature(int fd, float *temperature) {
    int retries = 3;
    while (retries > 0) {
        if (oneWireReset(fd) == 0) {
            // Skip ROM command
            oneWireWrite(fd, 0xCC);

            // Start temperature conversion command
            oneWireWrite(fd, 0x44);

            delay(800); // Wait for conversion (at least 750ms)

            if (oneWireReset(fd) == 0) {
                // Skip ROM command
                oneWireWrite(fd, 0xCC);

