                printf("Temperature falls below low threshold. Turning LED blue.\n");
                control_led(0, 0, 1);
                log_event(temperature, "Low Temperature Alert");
            } else {
                printf("Temperature within acceptable range. Turning LED green.\n");
                control_led(0, 1, 0);
            }
