    int fd = wiringPiOneWireSetup(pin);
    if (fd == -1) {
        fprintf(stderr, "Error: Failed to initialize 1-Wire on pin %d\n", pin);
        return -1;
    }

    if (oneWireReset(fd) != 0) {
        fprintf(stderr, "Error: Reset failed on pin %d\n", pin);
        return -1;
    }

    oneWireWriteByte(fd, 0x44); // Convert temperature
    delay(750); // Wait for conversion

    if (oneWireReset(fd) != 0) {
        fprintf(stderr, "Error: Reset failed on pin %d\n", pin);
        return -1;
    }

    oneWireWriteByte(fd, 0xBE); // Read scratchpad
    int16_t rawTemperature = (oneWireReadByte(fd) << 8) | oneWireReadByte(fd);

    *temperature = (float)rawTemperature / 16.0;

    return 0;
}

