void signalHandler(int signum) {
    if (signum == SIGINT) {
        printf("Ctrl+C pressed. Exiting gracefully.\n");
        keepRunning = 0;
    }
}

// Function to get temperature reading from DS18B20 sensor
float getTemperature(int pin) {
    float temp = -999.0;
    int sensorId = wiringPi1WireSelect(pin);
    if (sensorId < 0) {
        fprintf(stderr, "Error: Could not select sensor on pin %d. Error code: %d\n", pin, sensorId);
        return -999.0; // Indicate error
    }

    int status = wiringPi1WireRead(pin);
    if (status < 0) {
        fprintf(stderr, "Error: Could not read data from sensor on pin %d. Error code: %d\n", pin, status);
        return -999.0; // Indicate error
    }

    temp = (float)wiringPi1WireRead(pin);
    return temp;
}

// Function to log temperature and timestamp to a file
void logTemperature(float temp, const char *filename) {
    FILE *fp = fopen(filename, "a");
    if (fp == NULL) {
        fprintf(stderr, "Error: Could not open file %s for writing.\n", filename);
        return;
    }

    time_t t = time(NULL);
    struct tm tm = *localtime(&t);
    fprintf(fp, "%d-%02d-%02d %02d:%02d:%02d, %.2f\n", tm.tm_year + 1900, tm.tm_mon + 1, tm.tm_mday, tm.tm_hour, tm.tm_min, tm.tm_sec, temp);
    fclose(fp);
}

