void controlLED(int pin, int red, int green, int blue) {
    digitalWrite(pin, HIGH);
    delay(red);
    digitalWrite(pin, LOW);
    delay(green);
    digitalWrite(pin, HIGH);
    delay(blue);
    digitalWrite(pin, LOW);
}

