    if (wiringPiSetup() == -1) {
        fprintf(stderr, "Error: Failed to initialize wiringPi.\n");
        return 1;
    }

    pinMode(GPIO_PIN, INPUT); // DS18B20 pin is an input
    pinMode(LED_PIN, OUTPUT);

    signal(SIGINT, signalHandler);

    float threshold = 25.0; // Default threshold

    // Check command-line arguments for threshold
    if (argc > 1) {
        threshold = atof(argv[1]);
        if (threshold <= 0.0) {
            fprintf(stderr, "Error: Invalid threshold value. Using default threshold of 25.0\n");
            threshold = 25.0;
        }
    }

    printf("Temperature monitoring started. Threshold: %.2f\n", threshold);

    while (keepRunning) {
        float temp = getTemperature(GPIO_PIN);
        if (temp > -998.0) { // Check for valid temperature reading
            printf("Temperature: %.2f\n", temp);
            logTemperature(temp, LOG_FILE);

            if (temp > threshold) {
                printf("Temperature above threshold (%.2f > %.2f). Triggering alert.\n", temp, threshold);
                controlLED(LED_PIN, 0, 500, 0); // Red for 0ms, Green for 500ms, Blue for 0ms
            }
        } else {
            fprintf(stderr, "Error: Invalid temperature reading.\n");
        }

        delay(5000); // Check every 5 seconds
    }

    printf("Temperature monitoring stopped.\n");
    return 0;
}

