// Function to handle CLK interrupt
void clk_interrupt(int gpio, int level, uint32_t tick) {
    // Check for rising edge
    if (level == 1) {
        // Determine direction based on DT pin
        if (gpioRead(DT_PIN) == 0) {
            encoder_position++;
        } else {
            encoder_position--;
        }

        // Ensure position is within bounds
        if (encoder_position < 0) {
            encoder_position = 0;
        } else if (encoder_position > 3) {
            encoder_position = 3;
        }

        // Set buzzer frequency based on encoder position
        switch (encoder_position) {
            case POSITION_1:
                set_frequency(1000);
                break;
            case POSITION_2:
                set_frequency(2000);
                break;
            case POSITION_3:
                set_frequency(3000);
                break;
            case POSITION_4:
                set_frequency(4000);
                break;
            default:
                set_frequency(0); // Turn off buzzer if out of bounds
                break;
        }
    }
}

