                set_frequency(3000);
                break;
            case POSITION_4:
                set_frequency(4000);
                break;
            default:
                set_frequency(0); // Turn off buzzer if out of bounds
                break;
        }
    }
}

// Function to set the buzzer frequency
void set_frequency(int frequency) {
    if (frequency == 0) {
        gpioHardwarePWM(BUZZER_PIN, 0, 0); // Turn off PWM
    } else {
        gpioHardwarePWM(BUZZER_PIN, frequency, 500000); // Set PWM frequency and duty cycle
    }
}

