// Function to read the analog value from the MCP3008
int read_sensor(int gpio_pin)
{
    int handle;
    unsigned char tx_buf[3];
    unsigned char rx_buf[3];

    // Construct SPI message
    tx_buf[0] = 0x01;                  // Start bit
    tx_buf[1] = ((gpio_pin & 0x07) << 4) | 0x80; // Single-ended mode, channel 0-7
    tx_buf[2] = 0x00;                  // Don't care

    handle = spiOpen(SPI_CHANNEL, SPI_SPEED, SPI_MODE);
    if (handle < 0) {
        fprintf(stderr, "Error opening SPI channel: %s\n", strerror(errno));
        return -1;
    }

    // Transfer SPI message
    spiXfer(handle, tx_buf, rx_buf, 3);

    spiClose(handle);

    // Extract ADC value (10 bits)
    int adc_value = ((rx_buf[1] & 0x03) << 8) + rx_buf[2];

    return adc_value;
}

// Function to convert ADC value to voltage
double get_voltage(int sensor_value)
{
    // MCP3008 has a 3.3V reference, so the voltage is calculated as:
    // voltage = (sensor_value / 1023.0) * 3.3
    return (sensor_value / 1023.0) * 3.3;
}

